import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useApp } from '../AppContext';
import { ProjectCategory, Project } from '../types';
import { Logo } from '../constants';

export const Admin: React.FC = () => {
  const { theme, setTheme, projects, setProjects, messages, adminPassword, setAdminPassword } = useApp();
  const [activeTab, setActiveTab] = useState<'projects' | 'theme' | 'messages' | 'dashboard' | 'security'>('dashboard');

  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [tempTheme, setTempTheme] = useState(theme);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newProject, setNewProject] = useState<Partial<Project>>({
    category: ProjectCategory.APARTMENT,
    visible: true,
    detailImages: []
  });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === adminPassword) {
      setIsAuthenticated(true);
      setLoginError(false);
    } else {
      setLoginError(true);
    }
  };

  const handleSaveTheme = () => {
    setTheme(tempTheme);
    alert('테마 설정이 저장되었습니다.');
  };

  const handleSaveProject = () => {
    if (editingId) {
      setProjects(projects.map(p => p.id === editingId ? { ...p, ...newProject } as Project : p));
      setEditingId(null);
    } else {
      const p = {
        ...newProject,
        id: Date.now().toString(),
        date: new Date().toISOString().split('T')[0],
        visible: newProject.visible ?? true,
        detailImages: newProject.detailImages || []
      } as Project;
      setProjects([p, ...projects]);
      setIsAdding(false);
    }
    setNewProject({ category: ProjectCategory.APARTMENT, visible: true, detailImages: [] });
  };

  const deleteProject = (id: string) => {
    if (confirm('정말 삭제하시겠습니까?')) {
      setProjects(projects.filter(p => p.id !== id));
    }
  };

  const toggleVisibility = (id: string) => {
    setProjects(projects.map(p => p.id === id ? { ...p, visible: !p.visible } : p));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-[#F2EFE9] flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 text-center space-y-8 animate-in zoom-in duration-500">
          <div className="flex flex-col items-center gap-4">
            <Logo color={theme.primaryColor} />
            <h1 className="font-serif text-3xl font-bold tracking-tight" style={{ color: theme.primaryColor }}>
              {theme.brandName} Admin
            </h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input
              autoFocus
              type="password"
              placeholder="Password"
              className={`w-full bg-gray-50 border-none rounded-xl p-5 text-center focus:ring-2 outline-none transition-all ${
                loginError ? 'ring-2 ring-red-400' : 'focus:ring-blue-500'
              }`}
              value={passwordInput}
              onChange={(e) => {
                setPasswordInput(e.target.value);
                setLoginError(false);
              }}
            />
            <button
              type="submit"
              className="w-full py-4 rounded-xl text-white font-bold text-lg shadow-lg"
              style={{ backgroundColor: theme.primaryColor }}
            >
              Login
            </button>
          </form>
          <Link to="/" className="inline-block text-gray-300 text-xs uppercase tracking-widest font-bold">
            Back to Website
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex">
      <aside className="w-64 bg-[#2B4360] text-white p-8 space-y-12 shrink-0">
        <div className="flex items-center gap-3">
          <Logo color="#fff" />
          <span className="font-serif font-bold text-xl">Admin</span>
        </div>
        <nav className="space-y-2">
          {['dashboard', 'projects', 'theme', 'messages', 'security'].map((id) => (
            <button
              key={id}
              onClick={() => setActiveTab(id as any)}
              className={`w-full text-left px-4 py-3 rounded-lg transition-colors flex items-center gap-3 ${
                activeTab === id ? 'bg-white/10' : 'opacity-60 hover:opacity-100'
              }`}
            >
              {id.charAt(0).toUpperCase() + id.slice(1)}
            </button>
          ))}
        </nav>
      </aside>

      <main className="flex-grow p-12 overflow-y-auto h-screen">
        {activeTab === 'projects' && (
          <div className="space-y-8 animate-in fade-in duration-300">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-bold">포트폴리오 관리</h2>
              <button
                onClick={() => { setIsAdding(true); setEditingId(null); setNewProject({ category: ProjectCategory.APARTMENT, visible: true, detailImages: [] }); }}
                className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold"
              >
                + 새 프로젝트 추가
              </button>
            </div>

            {(isAdding || editingId) && (
              <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200 space-y-6">
                <h3 className="text-xl font-bold">{editingId ? '프로젝트 수정' : '새 프로젝트'}</h3>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-500">제목</label>
                    <input type="text" className="w-full border p-3 rounded-lg" value={newProject.title || ''} onChange={e => setNewProject({...newProject, title: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-500">카테고리</label>
                    <select className="w-full border p-3 rounded-lg" value={newProject.category} onChange={e => setNewProject({...newProject, category: e.target.value})}>
                      {Object.values(ProjectCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-500">Before 이미지 URL</label>
                    <input type="text" className="w-full border p-3 rounded-lg" value={newProject.beforeImage || ''} onChange={e => setNewProject({...newProject, beforeImage: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-500">대표(After) 이미지 URL</label>
                    <input type="text" className="w-full border p-3 rounded-lg" value={newProject.afterImage || ''} onChange={e => setNewProject({...newProject, afterImage: e.target.value})} />
                  </div>
                  <div className="col-span-2 space-y-2">
                    <label className="text-sm font-bold text-gray-500 block">상세 사진 URL들 (줄바꿈으로 구분)</label>
                    <textarea 
                      rows={4} 
                      className="w-full border p-3 rounded-lg font-mono text-sm" 
                      placeholder="https://image1.jpg&#10;https://image2.jpg"
                      value={newProject.detailImages?.join('\n') || ''}
                      onChange={e => setNewProject({...newProject, detailImages: e.target.value.split('\n').filter(url => url.trim() !== '')})}
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-gray-500">설명</label>
                  <textarea rows={4} className="w-full border p-3 rounded-lg" value={newProject.description || ''} onChange={e => setNewProject({...newProject, description: e.target.value})} />
                </div>
                <div className="flex gap-4">
                  <button onClick={handleSaveProject} className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold">저장하기</button>
                  <button onClick={() => { setIsAdding(false); setEditingId(null); }} className="bg-gray-200 px-8 py-3 rounded-lg font-bold">취소</button>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 gap-4">
              {projects.map(p => (
                <div key={p.id} className="bg-white p-4 rounded-xl flex items-center justify-between border border-gray-200">
                  <div className="flex items-center gap-4">
                    <img src={p.afterImage} className="w-16 h-16 object-cover rounded-lg" alt="" />
                    <div>
                      <h4 className="font-bold">{p.title}</h4>
                      <p className="text-xs text-gray-400">{p.detailImages?.length || 0} 개의 상세 사진</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => { setEditingId(p.id); setNewProject(p); setIsAdding(false); }} className="p-2 text-blue-600 font-bold text-xs">수정</button>
                    <button onClick={() => deleteProject(p.id)} className="p-2 text-red-600 font-bold text-xs">삭제</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Other tabs remain similar logic */}
        {activeTab === 'dashboard' && <div className="p-20 text-center opacity-30">Dashboard Content</div>}
        {activeTab === 'theme' && <div className="p-20 text-center opacity-30">Theme Content</div>}
        {activeTab === 'messages' && <div className="p-20 text-center opacity-30">Messages Content</div>}
        {activeTab === 'security' && <div className="p-20 text-center opacity-30">Security Content</div>}
      </main>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../AppContext';
import { BeforeAfterSlider } from '../components/BeforeAfterSlider';
import { ProjectCategory, Project } from '../types';

export const Portfolio: React.FC = () => {
  const { projects, theme } = useApp();
  const [filter, setFilter] = useState<string>('All');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  const categories = ['All', ...Object.values(ProjectCategory)];

  const visibleProjects = projects.filter(p => p.visible === true);

  const filteredProjects = filter === 'All'
    ? visibleProjects
    : visibleProjects.filter(p => p.category === filter);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setSelectedProject(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  return (
    <div className="min-h-screen py-20 px-6 animate-in fade-in duration-700">
      <div className="max-w-7xl mx-auto">
        <header className="mb-20">
          <h2 className="font-serif text-5xl md:text-7xl mb-8">Our Works</h2>
          <p className="text-gray-500 text-lg max-w-2xl leading-relaxed">
            레이어드필름이 시공한 다양한 공간들의 변화를 만나보세요. <br />
            아파트부터 상업공간까지, 모든 공간에 최적화된 마감을 제안합니다.
          </p>
        </header>

        {/* Filter Buttons */}
        <div className="flex flex-wrap gap-4 mb-16">
          {categories.map((cat) => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`px-8 py-3 rounded-full text-sm font-semibold transition-all ${
                filter === cat
                  ? 'text-white shadow-xl'
                  : 'bg-white text-gray-400 hover:text-black hover:bg-gray-100'
              }`}
              style={filter === cat ? { backgroundColor: theme.primaryColor } : {}}
            >
              {cat}
            </button>
          ))}
